import { Schema, model } from 'mongoose';

interface User {
  id: string;
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const userSchema = new Schema<User>({
  username: {
    type: String,
    required: true,
    unique: true
  },
  passwordHash: {
    type: String,
    required: true
  },
  email: {
    type: String,
    required: true,
    unique: true
  },
  createdAt: {
    type: Date,
    default: Date.now
  }
});

export const UserModel = model<User>('User', userSchema);

import { UserModel } from './user.model';

export class UserRepository {
  async findById(id: string) {
    return UserModel.findById(id).exec();
  }

  async findByUsername(username: string) {
    return UserModel.findOne({ username }).exec();
  }

  async createUser(user: Omit<User, 'id'>) {
    const newUser = new UserModel(user);
    return newUser.save();
  }
}

export interface UserDTO {
  id: string;
  username: string;
  email: string;
  createdAt: Date;
}

export const toUserDTO = (user: any): UserDTO => {
  return {
    id: user._id,
    username: user.username,
    email: user.email,
    createdAt: user.createdAt
  };
};

import { z } from 'zod';

export const registerUserSchema = z.object({
  username: z.string().min(3),
  password: z.string().min(6),
  email: z.string().email(),
});

export const loginUserSchema = z.object({
  username: z.string().min(3),
  password: z.string().min(6),
});

import { UserRepository } from './user.repository';
import { UserDTO, toUserDTO } from './user.dto';
import bcrypt from 'bcrypt';

export class UserService {
  private userRepository = new UserRepository();

  async registerUser(username: string, password: string, email: string): Promise<UserDTO> {
    const passwordHash = await bcrypt.hash(password, 10);
    const user = await this.userRepository.createUser({ username, passwordHash, email, createdAt: new Date() });
    return toUserDTO(user);
  }

  async validateUser(username: string, password: string): Promise<UserDTO | null> {
    const user = await this.userRepository.findByUsername(username);
    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      return null;
    }
    return toUserDTO(user);
  }
}

import { Request, Response } from 'express';
import { UserService } from './user.service';
import { registerUserSchema, loginUserSchema } from './user.validator';
import { AppError } from '../../utils/app-error';

export class UserController {
  private userService = new UserService();

  async register(req: Request, res: Response): Promise<void> {
    const validationResult = registerUserSchema.safeParse(req.body);
    if (!validationResult.success) {
      throw new AppError('InvalidInput', 'Input validation failed', 400);
    }

    const { username, password, email } = validationResult.data;
    const user = await this.userService.registerUser(username, password, email);
    res.status(201).json({ success: true, data: user });
  }

  async login(req: Request, res: Response): Promise<void> {
    const validationResult = loginUserSchema.safeParse(req.body);
    if (!validationResult.success) {
      throw new AppError('InvalidInput', 'Input validation failed', 400);
    }

    const { username, password } = validationResult.data;
    const user = await this.userService.validateUser(username, password);
    if (!user) {
      throw new AppError('AuthenticationFailed', 'Invalid credentials', 401);
    }
    // Here should be created JWT token for future use
    res.json({ success: true, data: { token: 'JWT_TOKEN_PLACEHOLDER' } });
  }
}
